    26→    let mut se = Vec::new();
    27→    for i in 0..vcov.nrows() {
    28→        se.push(vcov[[i, i]].sqrt());
    29→    }
    30→    se
    31→}
    32→
    33→/// Compute t-statistics given coefficients and standard errors  
    34→pub fn t_statistics(coefficients: &[f64], std_errors: &[f64]) -> Vec<f64> {
    35→    coefficients
    36→        .iter()
    37→        .zip(std_errors.iter())
    38→        .map(|(coef, se)| coef / se)
    39→        .collect()
    40→}
    41→
    42→/// Compute two-tailed p-values from t-statistics
    43→pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Vec<f64> {
    44→    t_stats
    45→        .iter()
    46→        .map(|&t| {
    47→            // Two-tailed p-value: P(|T| > |t|) = 2 * P(T > |t|)
    48→            let abs_t = t.abs();
    49→            2.0 * (1.0 - t_cdf(abs_t, df))
    50→        })
    51→        .collect()
    52→}
    53→
    54→/// Cumulative distribution function for Student's t-distribution using statrs
    55→fn t_cdf(t: f64, df: i32) -> f64 {
    56→    if df <= 0 {
    57→        return 0.5; // Invalid df, return neutral p-value
    58→    }
    59→
    60→    if t.is_infinite() {
    61→        return if t > 0.0 { 1.0 } else { 0.0 };
    62→    }
    63→
    64→    match StudentsT::new(0.0, 1.0, df as f64) {
    65→        Ok(dist) => dist.cdf(t),
    66→        Err(_) => 0.5, // Fallback for invalid parameters
    67→    }
    68→}
    69→
    70→/// Compute F-statistic p-value using F-distribution
    71→///
    72→/// For F(f; df1, df2) = P(F ≤ f), where F follows F-distribution with df1, df2 degrees of freedom
    73→pub fn f_test_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
    74→    if f_stat <= 0.0 || df1 <= 0 || df2 <= 0 {
    75→        return 1.0;
    76→    }
    77→
    78→    match FisherSnedecor::new(df1 as f64, df2 as f64) {
    79→        Ok(dist) => 1.0 - dist.cdf(f_stat), // P(F > f_stat)
    80→        Err(_) => 1.0,                      // Fallback for invalid parameters
    81→    }
    82→}
    83→
    84→/// Calculate overall F-statistic for model significance
    85→/// Tests null hypothesis that all non-intercept coefficients are zero
    86→pub fn model_f_statistic(rss_full: f64, rss_null: f64, df_model: usize, df_resid: usize) -> f64 {
    87→    if df_model == 0 || df_resid == 0 || rss_full <= 0.0 {
    88→        return 0.0;
    89→    }
    90→
