    92→    let mse_model = explained_ss / df_model as f64;
    93→    let mse_resid = rss_full / df_resid as f64;
    94→
    95→    if mse_resid <= 0.0 {
    96→        return f64::INFINITY;
    97→    }
    98→
    99→    mse_model / mse_resid
